mapper.select:
select YYYY, SEL_CODE, SITE as SITE_ORG, CASE WHEN SITE='HQ' Then '본사' WHEN SITE='VN' then 'VINA' else site end as SITE, DEPT, DEPT_NAME, EXPEN_AREA FROM doi_dept where 1=1
and yyyy = #{yyyy}
and site = #{site}
order BY dept ;

DROP TABLE IF EXISTS #TempTable1;

CREATE TABLE #TempTable1 (
	YYYY varchar(10) COLLATE Korean_Wansung_CI_AS NOT NULL,
	SEL_CODE varchar(10) COLLATE Korean_Wansung_CI_AS NOT NULL,
	SITE varchar(4) COLLATE Korean_Wansung_CI_AS NOT NULL,
	DEPT varchar(10) COLLATE Korean_Wansung_CI_AS NOT NULL,
	DEPT_NAME nvarchar(30) COLLATE Korean_Wansung_CI_AS NULL,
	EXPEN_AREA nvarchar(30) COLLATE Korean_Wansung_CI_AS NULL
);

INSERT INTO #TempTable1
(
YYYY
, SEL_CODE
, SITE
, DEPT
, DEPT_NAME
, EXPEN_AREA
)
VALUES

	(
	#{item.field2}
	, #{item.field3}
	, #{item.field4}
	, #{item.field6}
	, #{item.field7}
	, #{item.field8}
	)
;

SELECT * FROM #TempTable1 a
WHERE EXISTS (
	SELECT 1
	FROM DOI_DEPT b
	WHERE 1=1
	AND b.YYYY = a.YYYY
	AND b.SITE = a.SITE
	AND b.DEPT = a.DEPT
);

mapper.insert:
CREATE TABLE #TempTable (
	seq_no INT,
	YYYY varchar(10) COLLATE Korean_Wansung_CI_AS NOT NULL,
	SEL_CODE varchar(10) COLLATE Korean_Wansung_CI_AS NOT NULL,
	SITE varchar(4) COLLATE Korean_Wansung_CI_AS NOT NULL,
	DEPT varchar(10) COLLATE Korean_Wansung_CI_AS NOT NULL,
	DEPT_NAME nvarchar(30) COLLATE Korean_Wansung_CI_AS NULL,
	EXPEN_AREA nvarchar(30) COLLATE Korean_Wansung_CI_AS NULL
);

INSERT INTO #TempTable
(
seq_no
, YYYY
, SEL_CODE
, SITE
, DEPT
, DEPT_NAME
, EXPEN_AREA
)
VALUES

	(
	#{item.field1}
	, #{item.field2}
	, #{item.field3}
	, #{item.field4}
	, #{item.field6}
	, #{item.field7}
	, #{item.field8}
	)
;

INSERT INTO DOI_DEPT (YYYY,SEL_CODE,SITE,DEPT,DEPT_NAME,EXPEN_AREA)
SELECT YYYY,SEL_CODE,SITE,DEPT,DEPT_NAME,EXPEN_AREA
FROM (
	SELECT *, MAX(seq_no) over (partition by YYYY, SITE, DEPT) max_seq_no FROM #TempTable
)A
WHERE 1=1
AND seq_no = max_seq_no
AND NOT EXISTS (
	SELECT 1
	FROM DOI_DEPT b
	WHERE 1=1
	AND b.YYYY = a.YYYY
	AND b.SITE = a.SITE
	AND b.DEPT = a.DEPT
);

DROP TABLE #TempTable;

INSERT INTO DOI_DEPT
(
YYYY
, SEL_CODE
, SITE
, DEPT
, DEPT_NAME
, EXPEN_AREA
)
VALUES
(
#{yyyy}
, #{selCode}
, CASE WHEN #{site}='본사' Then 'HQ'  WHEN #{site}='VINA' then 'VN' else left(#{site},2) end
, #{dept}
, #{deptName}
, #{expenArea}
);

mapper.delete:
