mapper.update:
UPDATE DOI_DEPT
SET SEL_CODE = #{selCode}
, DEPT_NAME = #{deptName}
, EXPEN_AREA = #{expenArea}
WHERE 1=1
and yyyy = #{yyyy}
and site = CASE WHEN #{site}='본사' Then 'HQ'  WHEN #{site}='VINA' then 'VN' else left(#{site},2) end
and dept = #{dept}
;
